#include<bits/stdc++.h>
using namespace std;
long long a[1000010],t[36],base[36];
const long long mod=998244353;
int main()
{
    long long n,p=2;
    scanf("%lld",&n);
    base[0]=1;
    for(long long i=1;i<=32;i++)
    {
        base[i]=base[i-1]*2%mod;
    }
    for(long long i=1;i<=n-3;i++)
    {
        p=p*n%mod;
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        for(long long j=1;j<31;j++)
        {
            if(a[i]&(1<<(j-1)))
            {
                continue;
            }
            t[j]++;
        }
    }
    long long ans=0;
    for(long long i=0;i<31;i++)
    {
        ans+=base[i]*t[i+1]%mod*(n-t[i+1])%mod;
        ans%=mod;
    }
    printf("%lld",ans*p%mod);
    return 0;
}
